72	// blockingAgentRunner blocks Run until ctx cancels, then returns a non-zero
73	// exit code (mirroring what a real subprocess does when its context dies).
74	// startedAt is closed once Run is on the blocking select so tests can
75	// deterministically race their cancel write against the in-flight attempt.
76	type blockingAgentRunner struct {
77		startedAt chan struct{}
78		once      sync.Once
79	}
