81	func (r *blockingAgentRunner) Run(opts RunArgs) (*Result, error) {
82		r.once.Do(func() { close(r.startedAt) })
83		ctx := opts.Context
84		if ctx == nil {
85			ctx = context.Background()
86		}
87		<-ctx.Done()
88		return &Result{ExitCode: 1, Error: ctx.Err().Error()}, nil
89	}
