13	// runAgentViaService is the new RunAgent dispatch path that drives the
14	// agent through agentlib.FizeauService.Execute and drains the resulting event
15	// channel into a DDx Result. Old in-package code paths (RunAgent legacy
16	// loop, embeddedCompactionConfig, buildAgentProvider, findTool, and
17	// wrapProviderWithDeadlines) stay in place; this function does NOT call them.
18	//
19	// Stall detection: we delegate to the agent's StallPolicy. The agent
20	// emits a stall event then a final event with Status="stalled".
21	func runAgentViaService(r *Runner, opts RunArgs) (*Result, error) {
22		promptText, err := r.resolvePrompt(opts)
23		if err != nil {
24			return nil, err
25		}
26	
27		model := r.resolveModel(opts, "agent")
28		timeout := r.resolveTimeout(opts)
29		wallClock := r.resolveWallClock(opts)
30	
31		wd := opts.WorkDir
32		if wd == "" {
33			wd, _ = os.Getwd()
34		}
35	
36		// Construct the service. Reuses NewServiceFromWorkDir so provider/model
37		// routing data lands on the agent the same way every other DDx command
38		// constructs it (see serviceconfig.go).
39		svc, err := NewServiceFromWorkDir(wd)
40		if err != nil {
41			return nil, fmt.Errorf("agent: build service: %w", err)
42		}
43	
44		// Resolve where to write the per-request session log.
45		logDir := opts.SessionLogDir
46		if logDir == "" {
47			logDir = r.Config.SessionLogDir
48		}
49		if logDir == "" {
50			logDir = DefaultLogDir
51		}
52	
53		providerTimeout := ResolveProviderRequestTimeout(wd, opts.Provider, model, 0)
54	
55		// Build the public ExecuteRequest per CONTRACT-003.
56		req := agentlib.ServiceExecuteRequest{
57			Prompt:          promptText,
58			Model:           model,
59			Provider:        opts.Provider,
60			Harness:         "agent",
61			ModelRef:        opts.ModelRef,
62			Reasoning:       agentlib.Reasoning(opts.Effort),
63			Permissions:     opts.Permissions,
64			WorkDir:         wd,
65			Timeout:         wallClock,
66			IdleTimeout:     timeout,
67			ProviderTimeout: providerTimeout,
68			SessionLogDir:   logDir,
69			Metadata:        opts.Correlation,
70			Role:            opts.Role,
71			CorrelationID:   opts.CorrelationID,
72		}
73	
74		parentCtx := opts.Context
75		if parentCtx == nil {
76			parentCtx = context.Background()
77		}
78		ctx, cancel := context.WithCancel(parentCtx)
79		defer cancel()
80	
81		start := time.Now()
82		events, err := svc.Execute(ctx, req)
83		if err != nil {
84			return nil, fmt.Errorf("agent: execute: %w", err)
85		}
86	
87		final, routing, _ := drainServiceEvents(events)
88		elapsed := time.Since(start)
89	
90		result := &Result{
91			Harness:    "agent",
92			Model:      model,
93			DurationMS: int(elapsed.Milliseconds()),
94		}
95		if routing != nil {
96			result.Provider = routing.Provider
97			if routing.Model != "" {
98				result.Model = routing.Model
99			}
100			if routing.Harness != "" {
101				result.Harness = routing.Harness
102			}
103			if power, speed, cost, source := selectedRoutingCandidateMetrics(routing); power > 0 || speed > 0 || cost > 0 || source != "" {
104				result.PredictedPower = power
105				result.PredictedSpeedTPS = speed
106				result.PredictedCostUSDPer1kTokens = cost
107				result.PredictedCostSource = source
108			}
109		}
110		if final != nil {
111			// Normalized final text from the upstream harness (agent-32e8ff5e).
112			result.Output = final.FinalText
113			if final.Usage != nil {
114				// v0.9.1: Usage fields became *int so the API can distinguish
115				// "harness reported zero" from "harness didn't report". Treat
116				// nil as zero for DDx's int-valued result struct.
117				if final.Usage.InputTokens != nil {
118					result.InputTokens = *final.Usage.InputTokens
119				}
120				if final.Usage.OutputTokens != nil {
121					result.OutputTokens = *final.Usage.OutputTokens
122				}
123				if final.Usage.TotalTokens != nil {
124					result.Tokens = *final.Usage.TotalTokens
125				}
126			}
127			if final.CostUSD > 0 {
128				result.CostUSD = final.CostUSD
129			}
130			result.ExitCode = final.ExitCode
131			result.Error = final.Error
132			if final.RoutingActual != nil {
133				if result.Provider == "" {
134					result.Provider = final.RoutingActual.Provider
135				}
136				if final.RoutingActual.Model != "" {
137					result.Model = final.RoutingActual.Model
138				}
139				if final.RoutingActual.Harness != "" {
140					result.Harness = final.RoutingActual.Harness
141				}
142				if final.RoutingActual.Power > 0 {
143					result.ActualPower = final.RoutingActual.Power
144				}
145			}
146			if final.SessionLogPath != "" {
147				// surface as session ID for downstream cross-reference (mirrors
148				// the legacy path's AgentSessionID population).
149				result.AgentSessionID = final.SessionLogPath
150			}
151		}
152		result.Error = appendProviderTimeoutHint(result.Error, providerTimeout)
153	
154		promptSource := opts.PromptSource
155		if promptSource == "" {
156			if opts.PromptFile != "" {
157				promptSource = opts.PromptFile
158			} else {
159				promptSource = "inline"
160			}
161		}
162		r.logSession(result, len(promptText), promptText, promptSource, opts.Correlation)
163		r.recordRoutingOutcome(result, elapsed, opts)
164		return result, nil
165	}
