167	// drainServiceEvents reads service events and returns the final-event payload,
168	// the routing decision (when present in the routing_decision start event), and
169	// any canonical progress payloads emitted by the service.
170	func drainServiceEvents(events <-chan agentlib.ServiceEvent) (*agentlib.ServiceFinalData, *agentlib.ServiceRoutingDecisionData, []agentlib.ServiceProgressData) {
171		return drainServiceEventsWithWriter(events, nil)
172	}
173	
174	func drainServiceEventsWithWriter(events <-chan agentlib.ServiceEvent, w io.Writer) (*agentlib.ServiceFinalData, *agentlib.ServiceRoutingDecisionData, []agentlib.ServiceProgressData) {
175		var final *agentlib.ServiceFinalData
176		var routing *agentlib.ServiceRoutingDecisionData
177		var progress []agentlib.ServiceProgressData
178	
179		for ev := range events {
180			decoded, err := agentlib.DecodeServiceEvent(ev)
181			if err != nil {
182				continue
183			}
184			switch {
185			case decoded.RoutingDecision != nil:
186				routing = decoded.RoutingDecision
187				if w != nil {
188					if line := FormatServiceRoutingDecision(decoded.RoutingDecision); line != "" {
189						_, _ = fmt.Fprintln(w, line)
190					}
191				}
192			case decoded.Progress != nil:
193				progress = append(progress, *decoded.Progress)
194				if w != nil {
195					_, _ = fmt.Fprint(w, FormatServiceProgressEntries([]agentlib.ServiceProgressData{*decoded.Progress}))
196				}
197			case decoded.Final != nil:
198				final = decoded.Final
199			}
200		}
201		return final, routing, progress
202	}
203	
204	func selectedRoutingCandidateMetrics(routing *agentlib.ServiceRoutingDecisionData) (int, float64, float64, string) {
205		if routing == nil {
206			return 0, 0, 0, ""
207		}
208		for _, candidate := range routing.Candidates {
209			if candidate.Eligible && candidate.Model == routing.Model {
210				return candidate.Components.Power, candidate.Components.SpeedTPS, candidate.CostUSDPer1kTokens, candidate.CostSource
211			}
212		}
213		return 0, 0, 0, ""
214	}
