242	func endpointProviderName(providerType, baseURL string, endpoint ddxconfig.AgentEndpoint, index int) string {
243		host := endpoint.Host
244		port := endpoint.Port
245		if u, err := url.Parse(baseURL); err == nil {
246			if host == "" {
247				host = u.Hostname()
248			}
249			if port == 0 {
250				if p := u.Port(); p != "" {
251					if n, err := strconv.Atoi(p); err == nil {
252						port = n
253					}
254				}
255			}
256		}
257		parts := []string{providerType}
258		if host != "" {
259			parts = append(parts, host)
260		}
261		if port != 0 {
262			parts = append(parts, strconv.Itoa(port))
263		}
264		if len(parts) == 1 {
265			parts = append(parts, strconv.Itoa(index+1))
266		}
267		return sanitizeEndpointName(strings.Join(parts, "-"))
268	}
269	
270	func sanitizeEndpointName(s string) string {
271		s = strings.ToLower(strings.TrimSpace(s))
272		var b strings.Builder
273		lastDash := false
274		for _, r := range s {
275			keep := unicode.IsLetter(r) || unicode.IsDigit(r)
276			if keep {
277				b.WriteRune(r)
278				lastDash = false
279				continue
280			}
281			if !lastDash {
282				b.WriteByte('-')
283				lastDash = true
284			}
285		}
286		out := strings.Trim(b.String(), "-")
287		if out == "" {
288			return "endpoint"
289		}
290		return out
291	}
