1962	// that fetches origin and verifies ancestry before each bead claim. Fetch
1963	// failures are logged but do not block the worker (air-gap friendly).
1964	func buildCLIPreClaimHook(projectRoot string, gitOps agent.LandingGitOps) func(ctx context.Context) error {
1965		return func(ctx context.Context) error {
1966			branch, err := gitOps.CurrentBranch(projectRoot)
1967			if err != nil {
1968				return nil // can't determine branch — skip
1969			}
1970			res, err := gitOps.FetchOriginAncestryCheck(projectRoot, branch)
1971			if err != nil {
1972				if !strings.Contains(err.Error(), "git fetch origin") {
1973					return err
1974				}
1975				return nil // fetch failure is non-fatal
1976			}
1977			if res.Action == "diverged" {
1978				return fmt.Errorf("local branch %s has diverged from origin (local=%s origin=%s); reconcile manually before claiming",
1979					branch, res.LocalSHA, res.OriginSHA)
1980			}
1981			return nil
1982		}
1983	}
